SELECT COUNT(DISTINCT LP.PK) AS TOTAL FROM LATTES_P_PRODTEC LPP JOIN LATTES_PRODTEC LP ON LP.PK = LPP.FK_PRODTEC JOIN SERVIDOR S ON S.PK_SIAPE = LPP.FK_SIAPE WHERE LP.ANO = 2022 AND LOWER(LP.NATUREZA) = LOWER('parecer') AND S.SIGLA_CAMPUS = 'GYN' AND LOWER(COALESCE(S.AREA_INGRESSO, '')) LIKE '%ciencia da computacao%'